final:
module RefModule(  
    input wire [7:0] data_in1,  
    input wire [7:0] data_in2,  
    input wire control,  
    output reg [7:0] data_out  
);  
  wire [7:0] _tap_data_in1 = data_in1 & {8{1'b1}};


always @(*) begin  
    if (control)  
        data_out = data_in1;  
    else  
        data_out = data_in2;  
end  
endmodule
